                // Reads "email" + "roles" headers set by the API Gateway → populates SecurityContext
                .addFilterBefore(gatewayHeaderAuthFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

package com.hpethani.authservice.dto;

import com.hpethani.authservice.entity.Role;
import lombok.Data;

@Data
public class RegisterRequest {

    private String email;
    private String password;
    private Role role; // Optional: defaults to USER if not provided
}

package com.hpethani.authservice.dto;

import jakarta.validation.constraints.Email;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;
import lombok.Data;

@Data
public class RegisterRequest {

    @NotBlank(message = "Email is required")
    @Email(message = "Invalid email format")
    private String email;

    @NotBlank(message = "Password is required")
    @Size(min = 6, message = "Password must be at least 6 characters")
    private String password;

    // Role is NOT exposed to the client.
    // All self-registrations default to USER.
    // ADMIN users must be created manually or via a secured internal API.
}
